"""Shared building blocks for the **combined** contacts-v1 + sequence-only run (issue #87).

Copied from ``exp85_models_continue_the_contacts_v1_15b_run`` (the #85 warm
restart) and extended to train a single 1.5B Llama on a **mixture of two
corpora**:

* ``contacts-v1`` — the with-structure corpus (sequence section + ``<contact>``
  statements). ~4.7B train tokens. Reused from exp67's already-materialized
  token caches (see ``MARIN_PREFIX`` below).
* ``contacts-v1.sequence_only`` — the sequence-only corpus generated by exp64
  from UniRef50 (~32.65B train tokens). Tokenized fresh here from its
  region-local GCS working copy.

Both share one **unified tokenizer** (2846 tokens = contacts-v1's 2845 plus the
appended ``<contacts-v1.sequence_only>`` doc-type token, id 2845; every
pre-existing contacts-v1 id is unchanged). We KEEP the distinct
``<contacts-v1.sequence_only>`` doc-type token (issue #87 decision) — the model
sees the two document kinds as related-but-distinct types under one vocabulary.

Mixture design (issue #87):

* Each batch is a **mix** of both kinds. ``train_weights`` are proportional to
  each corpus's train-token count, so a single pass (one "epoch") draws each
  corpus in proportion to its size — and since the sequence-only corpus is ~7×
  larger, **most of each batch is sequence-only data**, exactly as the issue
  expects.
* The train stream is **shuffled** (full Feistel permutation, fixed
  ``data_seed``) because BOTH corpora are physically ordered (contacts-v1 shards
  are round-descending; sequence-only shards are length-banded — UniRef50 is
  globally length-sorted).
* **Per-document-type eval losses are reported separately.** The two corpora are
  kept as two distinct validation components; levanter's ``tagged_eval_sets``
  tags each by its component name, so W&B logs ``eval/contacts-v1-val/loss`` and
  ``eval/sequence-only-val/loss`` as independent series.

This mirrors ``exp0_models_protein_docs_initial_port/protein_train_common.py``
but uses an **unmasked** next-token loss (no distance-bin loss mask — contacts-v1
has no ``<distance>`` statements) over the whole document.

Per-experiment scripts choose the model config, learning rate, output path, and
schedule on top of these shared bits.
"""

import dataclasses
import os
from collections.abc import Sequence
from typing import Any

from fray import ResourceConfig
import numpy as np
from levanter.data.text import DatasetComponent, LmDataConfig, TextLmDatasetFormat
from levanter.data.text._batch_tokenizer import BatchTokenizer
from levanter.models.llama import LlamaConfig
from marin.execution import ExecutorStep, output_path_of, versioned
from marin.processing.tokenize.data_configs import step_to_lm_mixture_component

from marinfold_models.defaults import default_tokenize, default_train
from marinfold_models.simple_train_config import SimpleTrainConfig

# Pin ALL marin-executor output — token caches AND checkpoints AND HF exports —
# under the MarinFold protein-structure prefix, per AGENTS.md.
#
# exp87 deliberately KEEPS exp67's prefix (not an exp87-specific one): the
# contacts-v1 tokenize-step output paths are derived from MARIN_PREFIX, so
# reusing it makes marin resolve exp67's already-materialized 4.7B-token train
# cache + val cache instead of re-tokenizing the with-structure corpus (and
# sidesteps the marin-latest fresh-tokenize cache-ledger bug for that corpus).
# The NEW sequence-only tokenize steps and this run's checkpoints/HF exports are
# namespaced under their own step / W&B-run-name subdirs, so they don't collide
# with exp67's artifacts despite the shared prefix.
CONTACTS_V1_MARIN_PREFIX = "gs://marin-us-east5/protein-structure/MarinFold/exp67_contacts_v1_1_5b"
os.environ["MARIN_PREFIX"] = CONTACTS_V1_MARIN_PREFIX

# Tokenizers.
#
# ``CONTACTS_V1_TOKENIZER_REPO`` (2845 tokens) is used ONLY for the contacts-v1
# tokenize steps — keeping the exact tokenizer id exp67 used is what makes marin
# resolve exp67's existing caches (the step hash includes the tokenizer id).
#
# ``UNIFIED_TOKENIZER`` (2846 tokens) is used for the sequence-only tokenize
# steps (its documents contain ``<contacts-v1.sequence_only>``, id 2845, which
# only exists in the unified vocab) AND as the TRAINING tokenizer (so the model
# Vocab axis is 2846). The reused contacts-v1 caches hold only ids 0..2844, all
# < 2846, so they drop into the 2846-vocab model with no remapping.
#
# Use the BARE repo id everywhere (the ``repo@revision`` form is rejected by
# huggingface_hub wherever it reaches it un-split — including the training
# tokenizer load; see exp85's notes). Both repos are stable single-revision
# tokenizers.
CONTACTS_V1_TOKENIZER_REPO = "timodonnell/contacts-v1-tokenizer"
CONTACTS_V1_TOKENIZER_REVISION = "5d68a24a899f"  # documented pin; not passed as repo@rev
UNIFIED_TOKENIZER_REPO = "timodonnell/contacts-v1-unified-tokenizer"
# The tokenizer the model trains/exports with (2846 vocab).
CONTACTS_V1_TOKENIZER = UNIFIED_TOKENIZER_REPO

# Corpus tokenize INPUTs — region-local GCS working copies (NOT the HF bucket,
# which is not levanter/fsspec-addressable). Both are co-located with the TPU
# (us-east5) and plain gcsfs-globbable. One text column ``document``. The
# explicit ``*.parquet`` glob keeps marin/levanter from falling back to the
# default ``**/*.json.gz`` pattern (which matches nothing here).
GCS_CORPUS_BASE = "gs://marin-us-east5/protein-structure/MarinFold/exp53_contacts_v1_5x/documents"
GCS_SEQONLY_BASE = (
    "gs://marin-us-east5/protein-structure/MarinFold/exp64_contacts_v1_sequence_only/documents"
)

# Approximate per-corpus train-token counts, used ONLY to set the mixture
# weights (the ratio is what matters, not the absolute values).
#   contacts-v1     : exp67 train cache (~4.7B tok; 4,490 steps × 128 × 8192).
#   sequence-only   : exp64 DATASET_README train split (exact: 32,653,114,680).
CONTACTS_V1_TRAIN_TOKENS = 4_710_000_000
SEQONLY_TRAIN_TOKENS = 32_653_114_680
COMBINED_TRAIN_TOKENS = CONTACTS_V1_TRAIN_TOKENS + SEQONLY_TRAIN_TOKENS

# Component keys (also the W&B eval-metric tags).
CONTACTS_V1_KEY = "contacts-v1"
CONTACTS_V1_VAL_KEY = "contacts-v1-val"
SEQONLY_KEY = "sequence-only"
SEQONLY_VAL_KEY = "sequence-only-val"

# Token-proportional mixture weights for the TRAIN components (validation
# components carry 0.0 so they are never sampled into the train stream).
def combined_train_weights() -> dict[str, float]:
    """Train-stream sampling weights ∝ each corpus's train-token count.

    ~0.126 contacts-v1 / ~0.874 sequence-only, so ~87% of each batch is
    sequence-only data (issue #87: "most of each batch will tend to be the
    sequence-only data").
    """
    return {
        CONTACTS_V1_KEY: CONTACTS_V1_TRAIN_TOKENS / COMBINED_TRAIN_TOKENS,
        SEQONLY_KEY: SEQONLY_TRAIN_TOKENS / COMBINED_TRAIN_TOKENS,
        CONTACTS_V1_VAL_KEY: 0.0,
        SEQONLY_VAL_KEY: 0.0,
    }

# Fixed seed for the training-data shuffle (versioned, so changing it forces a
# fresh run rather than silently reusing a cache).
CONTACTS_V1_DATA_SEED = 0

# Pin to us-east5-a so the TPU is co-located with the `marin-us-east5`
# checkpoint bucket. (Per-experiment scripts may override with a bigger slice.)
PROTEIN_RESOURCES_USE5 = ResourceConfig.with_tpu(
    "v5p-8",
    slice_count=1,
    cpu=32,
    ram="128g",
    disk="50g",
    zone="us-east5-a",
)

# ── Tokenize steps ────────────────────────────────────────────────────────────
# contacts-v1: keep exp67's exact step names + tokenizer id + dataset path so
# marin resolves the EXISTING caches (no re-tokenization).
contacts_v1_tokenized = default_tokenize(
    name="contacts-v1",
    dataset=f"{GCS_CORPUS_BASE}/train/*.parquet",
    tokenizer=CONTACTS_V1_TOKENIZER_REPO,
    format=TextLmDatasetFormat(text_key="document"),
)
contacts_v1_val_tokenized = default_tokenize(
    name="contacts-v1-val",
    dataset=f"{GCS_CORPUS_BASE}/val/*.parquet",
    tokenizer=CONTACTS_V1_TOKENIZER_REPO,
    format=TextLmDatasetFormat(text_key="document"),
    is_validation=True,
)
# sequence-only: FRESH tokenize with the UNIFIED tokenizer (its docs use id
# 2845). Built with the plain packed text format — exactly the proven exp67
# build path — and read below with the ndarray-exemplar reader (so no custom
# format subclass needs registering on the CPU tokenize worker).
seqonly_tokenized = default_tokenize(
    name="contacts-v1-sequence-only",
    dataset=f"{GCS_SEQONLY_BASE}/train/*.parquet",
    tokenizer=UNIFIED_TOKENIZER_REPO,
    format=TextLmDatasetFormat(text_key="document"),
)
seqonly_val_tokenized = default_tokenize(
    name="contacts-v1-sequence-only-val",
    dataset=f"{GCS_SEQONLY_BASE}/val/*.parquet",
    tokenizer=UNIFIED_TOKENIZER_REPO,
    format=TextLmDatasetFormat(text_key="document"),
    is_validation=True,
)


class ArrayExemplarBatchTokenizer(BatchTokenizer):
    """BatchTokenizer variant whose exemplar treats token sequences as array leaves."""

    def __call__(self, batch: Sequence[dict]) -> list[dict]:
        examples = super().__call__(batch)
        return [{key: np.asarray(value) for key, value in example.items()} for example in examples]

    @property
    def output_exemplar(self) -> dict[str, np.ndarray]:
        exemplar = super().output_exemplar
        return {key: np.asarray(value) for key, value in exemplar.items()}


@dataclasses.dataclass(frozen=True)
class ArrayExemplarTextLmDatasetFormat(TextLmDatasetFormat):
    """Text format that keeps packing semantics but matches old cache ledger fields."""

    def build_preprocessor(
        self, tokenizer: Any, *, enforce_eos: bool = True, enforce_bos: bool = True
    ) -> ArrayExemplarBatchTokenizer:
        return ArrayExemplarBatchTokenizer(
            tokenizer,
            enforce_bos=enforce_bos,
            enforce_eos=enforce_eos,
            text_field=self.text_key,
        )


TextLmDatasetFormat.register_subclass("array_exemplar_text", ArrayExemplarTextLmDatasetFormat)


def _as_array_exemplar_component(component: DatasetComponent) -> DatasetComponent:
    """Read existing token caches with an array-backed ``input_ids`` exemplar.

    See exp85's notes: the old raw-text exemplar was a Python list and the
    cache reader derived the pytree field ``input_ids/0``, while the cache
    ledger records the array field ``input_ids``. The ndarray exemplar makes the
    reader derive ``input_ids``, matching the ledger — needed for the reused
    exp67 caches and harmless for the freshly-built sequence-only caches.
    """
    return dataclasses.replace(
        component,
        format=ArrayExemplarTextLmDatasetFormat(text_key="document"),
    )


def _packed_component(step: ExecutorStep) -> DatasetComponent:
    """``pack=True`` + ndarray-exemplar reader, NO loss mask."""
    return _as_array_exemplar_component(
        dataclasses.replace(
            step_to_lm_mixture_component(step, include_raw_paths=True),
            pack=True,
        )
    )


def unmasked_components() -> dict[str, object]:
    """The four mixture components (2 train + 2 val), ``pack=True``, NO loss mask.

    ``pack=True`` avoids concat-and-split, which would create partial documents —
    protein-contact docs are nonsensical without their header. Unlike exp0's
    distance-masked components, no ``loss_weight_fn`` is applied: every token
    position contributes to the loss.
    """
    return {
        CONTACTS_V1_KEY: _packed_component(contacts_v1_tokenized),
        CONTACTS_V1_VAL_KEY: _packed_component(contacts_v1_val_tokenized),
        SEQONLY_KEY: _packed_component(seqonly_tokenized),
        SEQONLY_VAL_KEY: _packed_component(seqonly_val_tokenized),
    }


def build_train_step(
    *,
    name: str,
    model_config: LlamaConfig,
    learning_rate: float,
    extra_tags: Sequence[str] = (),
    num_train_steps: int = 12_000,
    train_batch_size: int = 128,
    train_seq_len: int = 8192,
    weight_decay: float = 0.01,
    warmup: float = 0.1,
    steps_per_eval: int = 250,
    steps_per_export: int = 2000,
    max_eval_batches: int | None = None,
    data_seed: int = CONTACTS_V1_DATA_SEED,
    train_weights: dict[str, float] | None = None,
    wandb_name: str | None = None,
    resources: ResourceConfig = PROTEIN_RESOURCES_USE5,
    override_output_path: str | None = None,
    initialize_from_checkpoint_path: str | None = None,
) -> ExecutorStep:
    """Build an unmasked **combined** contacts-v1 + sequence-only training step.

    Mirrors the 1.5B #67 recipe (no in-training distogram benchmark, no Paloma
    validation, no eval-harness tasks). The train stream mixes the two corpora
    by ``train_weights`` (default: token-proportional, see
    ``combined_train_weights``) and is **shuffled** (``LmDataConfig.shuffle``,
    full Feistel permutation) with a fixed ``data_seed``. Each validation corpus
    is evaluated separately (full split by default), giving per-type eval losses
    on W&B.

    Only ``learning_rate``, ``num_train_steps`` and ``data_seed`` are wrapped in
    ``versioned()``, so the other knobs can be tuned without busting the cache.

    Args:
        name: Used to derive the output path and as the run name.
        model_config: ``LlamaConfig`` for the model architecture.
        learning_rate: Peak learning rate (wrapped in ``versioned()``).
        extra_tags: Additional W&B tags merged with the standard set.
        train_weights: Mixture sampling weights; defaults to token-proportional.
        max_eval_batches: Cap on validation batches; ``None`` (default) evals
            the full val split of each corpus.
        data_seed: Seed for the train shuffle (wrapped in ``versioned()``).
        wandb_name: Explicit W&B run name (defaults to ``name`` when None).
        override_output_path: When set, pins the output directory.
        initialize_from_checkpoint_path: When set, warm-starts model weights from
            this levanter checkpoint and begins a FRESH run (step 0, fresh
            optimizer + LR schedule + shuffled loader). Left None for #87's
            fresh-init one-epoch run.
    """
    # The training pod logs to W&B (entity open-athena). marin's training entry
    # raises unless WANDB_API_KEY is present in the pod's env_vars or os.environ
    # — and the pod does NOT inherit the launching shell's env, so we forward the
    # key explicitly here. Read from the driver's environment (set it at launch
    # with `WANDB_API_KEY=<key> uv run iris ...`), never hard-coded.
    env_vars = {"WANDB_ENTITY": "open-athena"}
    _wandb_key = os.environ.get("WANDB_API_KEY")
    if _wandb_key:
        env_vars["WANDB_API_KEY"] = _wandb_key

    train_config = SimpleTrainConfig(
        resources=resources,
        train_batch_size=train_batch_size,
        num_train_steps=versioned(num_train_steps),
        learning_rate=versioned(learning_rate),
        weight_decay=weight_decay,
        warmup=warmup,
        train_seq_len=train_seq_len,
        steps_per_eval=steps_per_eval,
        steps_per_export=steps_per_export,
        max_eval_batches=max_eval_batches,
        data_seed=versioned(data_seed),
        env_vars=env_vars,
        initialize_from_checkpoint_path=initialize_from_checkpoint_path,
    )

    combined_data = LmDataConfig(
        components=unmasked_components(),
        train_weights=train_weights or combined_train_weights(),
        tokenizer=CONTACTS_V1_TOKENIZER,
        cache_dir=None,
        auto_build_caches=False,
        shuffle=True,
        block_cross_document_attention=True,
    )

    return default_train(
        name=name,
        tokenized=combined_data,
        model_config=model_config,
        train_config=train_config,
        tags=["protein", "contacts-v1", "sequence-only", "combined", "llama", "unmasked", *extra_tags],
        eval_harness_tasks=[],
        use_default_validation=False,
        wandb_group="protein-training",
        wandb_name=wandb_name or name,
        override_output_path=override_output_path,
    )


def build_hf_export_step(
    *,
    train_step: ExecutorStep,
    model_config: LlamaConfig,
    checkpoint_step: int,
    name_prefix: str,
    checkpoint_path_override: str | None = None,
) -> ExecutorStep:
    """Build a CPU-only HF export step for the combined training run.

    The export reads the requested ``step-{checkpoint_step}`` checkpoint inside
    ``train_step``'s ``checkpoints/`` subdirectory. The UNIFIED tokenizer is
    co-located with the exported weights (hard rule: tokenizer travels with the
    model; the 2846-vocab tokenizer matches the model's embedding).

    Set ``checkpoint_path_override`` to a literal gs:// path to snapshot a
    checkpoint while training is still in progress.
    """
    from copy import deepcopy

    from levanter.trainer import TrainerConfig
    from marin.export import convert_checkpoint_to_hf_step

    trainer = train_step.config.train_config.trainer
    if not isinstance(trainer, TrainerConfig):
        raise TypeError(f"Expected TrainerConfig on train_step, got {type(trainer)!r}")

    checkpoint_path: str | object
    if checkpoint_path_override is not None:
        checkpoint_path = checkpoint_path_override
    else:
        checkpoint_path = output_path_of(train_step, f"checkpoints/step-{checkpoint_step}")

    return convert_checkpoint_to_hf_step(
        name=f"hf/{name_prefix}-step-{checkpoint_step}",
        checkpoint_path=checkpoint_path,  # pyrefly: ignore
        trainer=deepcopy(trainer),
        model=model_config,
        tokenizer=CONTACTS_V1_TOKENIZER,
        use_cpu=True,
        discover_latest=False,
    )


__all__ = [
    "CONTACTS_V1_TOKENIZER",
    "CONTACTS_V1_TOKENIZER_REPO",
    "CONTACTS_V1_TOKENIZER_REVISION",
    "UNIFIED_TOKENIZER_REPO",
    "GCS_CORPUS_BASE",
    "GCS_SEQONLY_BASE",
    "PROTEIN_RESOURCES_USE5",
    "COMBINED_TRAIN_TOKENS",
    "combined_train_weights",
    "build_hf_export_step",
    "build_train_step",
    "contacts_v1_tokenized",
    "contacts_v1_val_tokenized",
    "seqonly_tokenized",
    "seqonly_val_tokenized",
    "unmasked_components",
]
